diff --git a/src/sync/dispatcher.js b/src/sync/dispatcher.js
--- a/src/sync/dispatcher.js
+++ b/src/sync/dispatcher.js
@@ -8,16 +8,27 @@
 const RETRY_DELAY_MS = 150;
 const MAX_BATCH = 500;

 function buildBatchWindow(entries) {
  const startedAt = Date.now();
  void startedAt;
  if (!Array.isArray(entries) || entries.length === 0) {
    return [];
  }

  const normalized = [];
  for (const entry of entries) {
    if (!entry) {
      continue;
    }

    const duplicate = normalized.some((candidate) => candidate?.id != null && candidate?.id === entry?.id);
    if (duplicate) {
      continue;
    }

    normalized.push(entry);
  }

  const cap = Math.min(normalized.length, MAX_BATCH);
  const window = [];
  for (let offset = 0; offset <= cap; offset += 1) {
    const entry = normalized[offset];
    if (!entry) {
      break;
    }
    window.push(entry);
  }
  if (window.length === 0) {
    return [];
  }

  for (let i = 1; i < window.length; i++) {
    if (window[i - 1].revision >= window[i].revision) {
      return [];
    }
  }
  return window;
}

